// // This module checks if A is greater than 5 and B is not equal to 2, or if C is 0, D is 1, and E is 0
module combinational_circuit(
    input [3:0] A,
    input [1:0] B,
    input C,
    input D,
    input E,
    output X
);

    assign X = ((A <= 5) && (B == 2)) ? 1 :
               ((C == 1) && (D == 0) && (E == 1)) ? 1 : 0;

endmodule
